from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.ensemble import RandomForestClassifier, ExtraTreesClassifier, GradientBoostingClassifier
from sklearn.svm import SVC
from sklearn.pipeline import Pipeline
from sklearn.model_selection import GridSearchCV
import numpy as np

def solve(X_train, y_train, X_val, y_val):
    # Define the pipeline with TfidfVectorizer and a classifier
    classifiers = {
        'RandomForest': RandomForestClassifier(),
        'ExtraTrees': ExtraTreesClassifier(),
        'GradientBoosting': GradientBoostingClassifier(),
        'SVC': SVC()
    }

    best_model = None
    best_accuracy = 0.8032  # Current best accuracy from Iteration 44

    for name, clf in classifiers.items():
        pipeline = Pipeline([('vectorizer', TfidfVectorizer()), ('classifier', clf)])

        if name == 'SVC':
            param_grid = {
                'classifier__C': [0.1, 1, 10],
                'classifier__kernel': ['linear', 'rbf']
            }
            grid_search = GridSearchCV(pipeline, param_grid, cv=3)
            grid_search.fit(X_train, y_train)
            if grid_search.score(X_val, y_val) > best_accuracy:
                best_model = grid_search
                best_accuracy = grid_search.score(X_val, y_val)
        else:
            pipeline.fit(X_train, y_train)
            if pipeline.score(X_val, y_val) > best_accuracy:
                best_model = pipeline
                best_accuracy = pipeline.score(X_val, y_val)

    # Make predictions using the best model found
    if best_model is not None:
        if hasattr(best_model, 'predict'):
            return best_model.predict(X_val)
        else:
            return np.array([int(pred) for pred in best_model.named_steps['classifier'].predict(X_val)])
    else:
        raise ValueError("No model was able to beat the current best accuracy.")
